function normalizarTexto(valor) {
  return String(valor || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function palavrasDoNome(nome) {
  return normalizarTexto(nome)
    .split(" ")
    .filter(p => p.length >= 2);
}

function contarPalavrasIguais(nome1, nome2) {
  const palavras1 = new Set(palavrasDoNome(nome1));
  const palavras2 = new Set(palavrasDoNome(nome2));

  let iguais = 0;

  for (const palavra of palavras1) {
    if (palavras2.has(palavra)) {
      iguais++;
    }
  }

  return iguais;
}

function garantirArray(valor) {
  if (!valor) return [];

  if (Array.isArray(valor)) {
    return valor;
  }

  if (typeof valor === "string") {
    return valor
      .split(/,|;|\n/)
      .map(v => v.trim())
      .filter(Boolean);
  }

  return [valor];
}

// ================================
// LÊ TODOS OS ITENS DO MERGE
// ================================
const todos = $input.all().map(i => i.json);

// ================================
// SEPARA INPUTS
// ================================
const input1 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  i._totalPacientes !== undefined
);

const input2 = todos.filter(i =>
  i.PACIENTE &&
  Array.isArray(i.EXAMES) &&
  i._totalPacientes === undefined
);

// fallback caso venha tudo misturado
if (input2.length === 0) {
  const metade = Math.floor(todos.length / 2);

  input1.length = 0;
  input2.length = 0;

  input1.push(...todos.slice(0, metade));
  input2.push(...todos.slice(metade));
}

// ================================
// DADOS GERAIS
// ================================
