  input1[0]?.posto ||
  input2[0]?.posto ||
  "";

const data =
  input1[0]?.data ||
  input2[0]?.data ||
  "";

const resultado = [];

// ================================
// COMPARAÇÃO
// ================================
for (const item1 of input1) {

  const pacienteInput1 = item1.PACIENTE || "";
  const examesInput1 = garantirArray(item1.EXAMES);

  let melhorMatch = null;
  let maiorQtdPalavrasIguais = 0;

  // ================================
  // PROCURA MELHOR MATCH
  // ================================
  for (const item2 of input2) {

    const pacienteInput2 = item2.PACIENTE || "";

    const qtdPalavrasIguais = contarPalavrasIguais(
      pacienteInput1,
      pacienteInput2
    );

    if (qtdPalavrasIguais > maiorQtdPalavrasIguais) {
      maiorQtdPalavrasIguais = qtdPalavrasIguais;
      melhorMatch = item2;
    }
  }

  // ================================
  // VALIDAÇÃO DO NOME
  // PRIORIDADE:
  // 1. Nome completo igual
  // 2. Pelo menos 3 palavras iguais
  // ================================
  const nome1Normalizado =
    normalizarTexto(pacienteInput1);

  const nome2Normalizado =
    melhorMatch
      ? normalizarTexto(melhorMatch.PACIENTE || "")
      : "";

  const nomeCompletoIgual =
    nome1Normalizado === nome2Normalizado;

  const match3Palavras =
    maiorQtdPalavrasIguais >= 3;

  const matchPaciente = Boolean(
    melhorMatch &&
    (
      nomeCompletoIgual ||
      match3Palavras
    )
  );

  // ================================
  // DADOS INPUT2
  // ================================
  const pacienteInput2Encontrado =
    matchPaciente
      ? melhorMatch.PACIENTE || ""
      : "";

  const examesInput2 =
    matchPaciente
      ? garantirArray(melhorMatch.EXAMES)
      : [];

  // ================================
  // NORMALIZA EXAMES
  // ================================
  const examesInput1Norm =
    examesInput1.map(normalizarTexto);

  const examesInput2Norm =
    examesInput2.map(normalizarTexto);

  // ================================
  // EXAMES FALTANDO
  // ================================
  const examesFaltando =
    examesInput1.filter(exame =>
      !examesInput2Norm.includes(
        normalizarTexto(exame)
      )
    );

  // ================================
  // EXAMES EXTRAS
  // ================================
  const examesExtras =
    examesInput2.filter(exame =>
      !examesInput1Norm.includes(
        normalizarTexto(exame)
      )
    );

  // ================================
  // MATCH FINAL DOS EXAMES
  // ================================
  const matchExames =
    matchPaciente &&
    examesFaltando.length === 0 &&
    examesExtras.length === 0;

  // ================================
  // RESULTADO
  // ================================
  resultado.push({
    json: {

      posto,
      data,

      PACIENTE_INPUT1: pacienteInput1,
      PACIENTE_INPUT2: pacienteInput2Encontrado,

      matchPaciente,

      nomeCompletoIgual,

      matchPor3Palavras:
        !nomeCompletoIgual &&
        match3Palavras,

      palavrasIguaisPaciente:
        maiorQtdPalavrasIguais,

      matchExames,

      quantidadeExamesInput1:
        examesInput1.length,

      quantidadeExamesInput2:
        examesInput2.length,

      examesInput1,
      examesInput2,

      examesFaltandoNoInput2:
        examesFaltando,

      examesExtrasNoInput2:
        examesExtras,

      erro: !matchExames,

      mensagem:
        matchExames
          ? "Paciente e exames estão exatamente iguais"
          : matchPaciente
            ? "Paciente encontrado, mas há divergência entre os exames"
            : "Paciente não encontrado com nome completo igual nem com 3 palavras iguais"
    }
  });
}

return resultado;

