const item = $input.first();

let texto = String(
  item.json.extractedText ||
  item.json.markdown ||
  item.json.text ||
  item.json.pages?.map(p => p.markdown).join("\n") ||
  ""
)
  .replace(/\r/g, "\n")
  .replace(/\\n/g, "\n")
  .replace(/\\/g, "")
  .replace(/[ ]{2,}/g, " ")
  .trim();

const categoria = "(+)COMPUTADOR DO POSTO";

// =========================
// POSTO PELO NOME DO ARQUIVO
// =========================
let nomeArquivo = "";

try {
  nomeArquivo = $("ENVIO").first().json.name || "";
} catch (e) {}

const postoMatch = nomeArquivo.match(/\bP\s*(\d+)/i);
const posto = postoMatch ? postoMatch[1] : "";

// =========================
// DATA
// =========================
const dataMatch =
  texto.match(/Data do Envio:\s*(\d{2}\/\d{2}\/\d{4})/i) ||
  texto.match(/\[(\d{2}\/\d{2}\/\d{4})\s*-/) ||
  texto.match(/DIA\s*(\d{2})[./-](\d{2})[./-](\d{4})/i) ||
  texto.match(/(\d{2}\/\d{2}\/\d{4})/);

let data = "";

if (dataMatch) {
  if (dataMatch.length === 4) {
    data = `${dataMatch[1]}/${dataMatch[2]}/${dataMatch[3]}`;
  } else {
    data = dataMatch[1];
  }
}

// =========================
// TOTAL
// =========================
const totalMatch = texto.match(/No total de\s+(\d+)\s+Atendimentos/i);
const totalOficial = totalMatch ? Number(totalMatch[1]) : null;

// =========================
// FUNÇÕES
// =========================
function normalizarValor(v) {
  const s = String(v ?? "").trim();

  if (s.includes(",")) {
    return Number(s.replace(/\./g, "").replace(",", "."));
  }

  return Number(s);
}

function limparExames(txt) {
  return String(txt ?? "")
    .replace(/\[[^\]]*\]/g, "")
    .split(",")
    .map(e => e.trim())
    .filter(Boolean);
}

function adicionar(lista, paciente, examesTexto, valorTexto) {
  paciente = String(paciente ?? "").trim();
  examesTexto = String(examesTexto ?? "").trim();
  valorTexto = String(valorTexto ?? "").trim();

  if (!paciente || !examesTexto || !valorTexto) return;
  if (/paciente|exames|valor/i.test(paciente)) return;

  const exames = limparExames(examesTexto);
  const valor = normalizarValor(valorTexto);

  if (!exames.length || Number.isNaN(valor)) return;

  lista.push({
    sucesso: true,
    categoria,
    PACIENTE: paciente,
    EXAMES: exames,
    EXAMES_TEXTO: exames.join(", "),
    QTD_EXAMES: exames.length,
    VALOR: valor,
    posto,
    data
  });
}

// =========================
// EXTRAÇÃO
// =========================
const lista = [];
const linhas = texto.split("\n");

for (const linha of linhas) {
  let l = String(linha).trim();

  if (!l.includes("|")) continue;
  if (/Cod Integração|Cod Atend|Paciente|Exames|Valor|---/i.test(l)) continue;

  // Corrige OCR colado:
  // PLAQUETA33680 | TEREZA...
  l = l.replace(/([A-ZÁ-Úa-zá-ú])(\d{4,}\s*\|)/g, "$1\n$2");

  const subLinhas = l.split("\n");

  for (const sub of subLinhas) {
    const partes = sub
      .split("|")
      .map(c => c.trim())
      .filter(c => c !== "");

    // Formato antigo:
    // cod integração | cod atend | paciente | exames | valor
    if (partes.length >= 5 && /^\d+$/.test(partes[0]) && /^\d+$/.test(partes[1])) {
      adicionar(lista, partes[2], partes[3], partes[4]);
      continue;
    }

    // Formato novo/quebrado:
    // cod | paciente | exames | PARTICULAR | valor
    if (partes.length >= 5 && /^\d+$/.test(partes[0])) {
      adicionar(lista, partes[1], partes[2], partes[4]);
      continue;
    }
  }
}

// =========================
// REMOVE DUPLICADOS
// =========================
const unicos = [];
const vistos = new Set();

for (const item of lista) {
  const chave = `${item.PACIENTE}|${item.EXAMES_TEXTO}|${item.VALOR}`;

  if (!vistos.has(chave)) {
    vistos.add(chave);
    unicos.push(item);
  }
}

// =========================
// INDEXAÇÃO
// =========================
const total = totalOficial || unicos.length;

return unicos.map((item, i) => ({
  json: {
    ...item,
    _idx: i + 1,
    _totalPacientes: total
  }
}));

const item = $input.first();

const texto = String(
  item.json.extractedText ||
  item.json.text ||
  item.json.markdown ||
  item.json.pages?.map(p => p.markdown).join("\n") ||
  ""
)
  .replace(/\r/g, "\n")
  .replace(/[ ]{2,}/g, " ")
  .trim();

const categoria = "(+)COMPUTADOR DO POSTO";

// =========================
// POSTO PELO NOME DO ARQUIVO
// =========================
let nomeArquivo = "";

try {
  nomeArquivo = $("AT&TIC").first().json.name || "";
} catch (e) {}

try {
  if (!nomeArquivo) {
    nomeArquivo = $("ENVIO").first().json.name || "";
  }
} catch (e) {}

const matchPosto = nomeArquivo.match(/P\s*(\d+)/i);

const posto = matchPosto
  ? matchPosto[1]
  : (item.json.posto || "");

// =========================
// DATA
// =========================
const matchDataArquivo =
  nomeArquivo.match(/\d{2}\.\d{2}\.\d{4}/);

const dataArquivo = matchDataArquivo
  ? matchDataArquivo[0].replace(/\./g, "/")
  : "";

const dataTextoMatch =
  texto.match(/(\d{2}\/\d{2}\/\d{4})/);

const dataTexto =
  dataTextoMatch
    ? dataTextoMatch[1]
    : "";

const data = dataArquivo || dataTexto;

// =========================
// FUNÇÕES
// =========================
function normalizarValor(v) {
  const s = String(v || "").trim();

  if (s.includes(",")) {
    return Number(
      s
        .replace(/\./g, "")
        .replace(",", ".")
        .replace(/[^\d.]/g, "")
    );
  }

  return Number(
    s.replace(/[^\d.]/g, "")
  );
}

function limparExamesPorVirgula(txt) {
  return String(txt || "")
    .replace(/\[[^\]]*\]/g, "")
    .split(",")
    .map(e => e.trim())
    .filter(Boolean);
}

function examesPorEspaco(txt) {
  return String(txt || "")
    .replace(/\[[^\]]*\]/g, "")
    .split(/\s+/)
    .map(e => e.trim())
    .filter(Boolean);
}

function montarItem(
  paciente,
  exames,
  valor,
  dataLinha,
  extras = {}
) {
  return {
    sucesso: true,
    categoria,
    PACIENTE: String(paciente || "").trim(),
    EXAMES: exames,
    EXAMES_TEXTO: exames.join(", "),
    QTD_EXAMES: exames.length,
    VALOR: valor,
    posto,
    data: dataLinha || data,
    ...extras
  };
}

const lista = [];

const ehRelatorioMotoqueiro =
  /Relatório de Motoqueiros/i.test(texto);

// ======================================================
// RELATÓRIO DE MOTOQUEIRO
// ======================================================
if (ehRelatorioMotoqueiro) {

  // ======================================================
  // FORMATO 1
  // | DATA | COD | PACIENTE | EXAMES |
  // ======================================================
  const regexMotoqueiroTabela =
    /\|\s*(\d{2}\/\d{2}\/\d{4})\s*\|\s*(\d{6,})\s*\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|/g;

  let match;

  while ((match = regexMotoqueiroTabela.exec(texto)) !== null) {

    const dataLinha = match[1].trim();
    const paciente = match[3].trim();
    const examesTexto = match[4].trim();

    if (
      !paciente ||
      /paciente|---/i.test(paciente)
    ) {
      continue;
    }

    if (
      !examesTexto ||
      /exames|---/i.test(examesTexto)
    ) {
      continue;
    }

    const exames =
      examesPorEspaco(examesTexto);

    if (!exames.length) continue;

    lista.push(
      montarItem(
        paciente,
        exames,
        0,
        dataLinha
      )
    );
  }

  // ======================================================
  // LINHAS
  // ======================================================
  const linhas = texto
    .split("\n")
    .map(l => l.trim())
    .filter(Boolean);

  // ======================================================
  // FORMATO 2
  // DATA COD PACIENTE
  // EXAMES
  // ======================================================
  const regexLinhaPacienteMotoqueiro =
    /^(\d{2}\/\d{2}\/\d{4})\s+(\d{6,})\s+(.+)$/;

  for (let i = 0; i < linhas.length; i++) {

    const m =
      linhas[i].match(
        regexLinhaPacienteMotoqueiro
      );

    if (!m) continue;

    const dataLinha = m[1];
    const paciente = m[3].trim();

    const linhaExames =
      linhas[i + 1] || "";

    if (
      !linhaExames ||
      linhaExames.includes("|") ||
      /resumo|pacientes|exame|data de impressão|usuário|relatório|labovida/i.test(linhaExames)
    ) {
      continue;
    }

    const exames =
      examesPorEspaco(linhaExames);

    if (!exames.length) continue;

    lista.push(
      montarItem(
        paciente,
        exames,
        0,
        dataLinha
      )
    );
  }

  // ======================================================
  // FORMATO 3
  // DATA
  // CODIGO
  // PACIENTE
  // EXAMES
  // ======================================================
  for (let i = 0; i < linhas.length; i++) {

    const dataLinha = linhas[i];

    if (
      !/^\d{2}\/\d{2}\/\d{4}$/.test(dataLinha)
    ) {
      continue;
    }

    const codigo = linhas[i + 1] || "";

    if (!/^\d{6,}$/.test(codigo)) {
      continue;
    }

    const paciente =
      linhas[i + 2] || "";

    const examesTexto =
      linhas[i + 3] || "";

    if (
      !paciente ||
      !examesTexto ||
      /resumo|pacientes|exame|data de impressão|usuário|relatório|labovida/i.test(paciente) ||
      /resumo|pacientes|exame|data de impressão|usuário|relatório|labovida/i.test(examesTexto)
    ) {
      continue;
    }

    const exames =
      examesPorEspaco(examesTexto);

    if (!exames.length) continue;

    lista.push(
      montarItem(
        paciente,
        exames,
        0,
        dataLinha
      )
    );
  }
}

// ======================================================
// OUTROS FORMATOS
// ======================================================
if (!ehRelatorioMotoqueiro) {

  let match;

  // ======================================================
  // FORMATO LABORATÓRIO
  // ======================================================
  const regexLaboratorio =
    /\|\s*(\d+)\s*\|\s*(\d+)\s*\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|\s*([\d.,]+)\s*\|/g;

  while ((match = regexLaboratorio.exec(texto)) !== null) {

    const paciente =
      match[3].trim();

    const exames =
      limparExamesPorVirgula(match[4]);

    const valor =
      normalizarValor(match[5]);

    if (
      !paciente ||
      /paciente|exames|valor|cod/i.test(paciente)
    ) {
      continue;
    }

    if (
      !exames.length ||
      Number.isNaN(valor)
    ) {
      continue;
    }

    lista.push(
      montarItem(
        paciente,
        exames,
        valor,
        data
      )
    );
  }

  // ======================================================
  // FORMATO RECIBO MÉDICO
  // ======================================================
  const regexReciboMedico =
    /\|\s*(\d+)\s*\|\s*([^|]+?)\s*\|\s*([^|]+?)\s*\|\s*[^|]*\s*\|\s*([^|]+?)\s*\|\s*([\d.,]+)\s*\|/g;

  while ((match = regexReciboMedico.exec(texto)) !== null) {

    const paciente =
      match[2].trim();

    const examesTexto =
      match[3].trim();

    const convenio =
      match[4].trim();

    const valor =
      normalizarValor(match[5]);

    if (
      !paciente ||
      /paciente|total|atend/i.test(paciente)
    ) {
      continue;
    }

    if (
      !examesTexto ||
      /procedimentos|total/i.test(examesTexto)
    ) {
      continue;
    }

    if (
      examesTexto.toUpperCase() === "VOLTA"
    ) {
      continue;
    }

    if (
      Number.isNaN(valor)
    ) {
      continue;
    }

    const exames =
      limparExamesPorVirgula(examesTexto);

    if (!exames.length) continue;

    lista.push(
      montarItem(
        paciente,
        exames,
        valor,
        data,
        {
          CONVENIO: convenio
        }
      )
    );
  }
}

// ======================================================
// REMOVE DUPLICADOS
// ======================================================
const vistos = new Set();

const unicos = [];

for (const r of lista) {

  const chave =
    `${r.PACIENTE}|${r.EXAMES_TEXTO}|${r.data}`;

  if (!vistos.has(chave)) {
    vistos.add(chave);
    unicos.push(r);
  }
}

// ======================================================
// INDEXAÇÃO
// ======================================================
const total = unicos.length;

// ======================================================
// RETORNO
// ======================================================
return unicos.map((item, i) => ({
  json: {
    ...item,
    _idx: i + 1,
    _totalPacientes: total
  }
}));
